B.KB=new A.ae("Ama\xe7","Her b\xf6l\xfcmde kelime kartlar\u0131n\u0131 ait olduklar\u0131 kategorilere g\xf6re topla. Bir kategori kart\u0131n\u0131 yukar\u0131daki toplama alan\u0131na koyup o kategorinin t\xfcm kelimelerini \xfczerine ekleyerek kategoriyi bitir. Destedeki t\xfcm kategorileri bitirince b\xf6l\xfcm\xfc kazan\u0131rs\u0131n.")
B.Kt=new A.ae("Kartlar\u0131 dizme","Bir kelime kart\u0131n\u0131 yaln\u0131zca AYNI kategoriden bir kart\u0131n \xfczerine koyabilirsin. Kartlarda kategori yazmaz \u2014 hangi kelimenin nereye ait oldu\u011funu d\xfc\u015f\xfcnerek bulman gerekir. Yanl\u0131\u015f deneme hamle harcamaz, kart geri d\xf6ner.")
B.Kq=new A.ae("Kategori kartlar\u0131","Kategori kart\u0131n\u0131, e\u015fle\u015fen bir kelime zincirinin \xfczerine veya bo\u015f bir s\xfctuna koyabilirsin; koydu\u011fu s\xfctun kilitlenir. Kategori kart\u0131n\u0131 bo\u015f bir toplama slotuna \xe7ekti\u011finde alt\u0131ndaki e\u015fle\u015fen kelimeler de birlikte toplan\u0131r.")
B.KH=new A.ae("Hamleler","Her hareket, ta\u015f\u0131d\u0131\u011f\u0131n kart say\u0131s\u0131ndan ba\u011f\u0131ms\u0131z 1 hamledir. Desteden kart \xe7ekmek de 1 hamle. Hamle hakk\u0131n s\u0131n\u0131rl\u0131d\u0131r \u2014 \xfcstteki saya\xe7 kalan hamleni g\xf6sterir ve azal\u0131nca uyar\u0131 rengine d\xf6ner.")
B.Kr=new A.ae("Geri alma & kaybetme","Geri alma kredisiyle son hamleni geri sarabilirsin (krediler ba\u015far\u0131mlarla kazan\u0131l\u0131r). Hamle biterse ya da anlaml\u0131 hamle kalmazsa kaybedersin; b\xf6l\xfcm\xfc istedi\u011fin kadar \xfccretsiz yeniden ba\u015flatabilirsin.")
